Функция ТаблицаЗначенийВМассивСтруктур(ТаблицаЗначений)

	КолонкиТаблицы = Новый Массив;
	Для каждого Колонка Из ТаблицаЗначений.Колонки Цикл
		КолонкиТаблицы.Добавить(Колонка.Имя);
	КонецЦикла;
	СтрокаКолонок = СтрСоединить(КолонкиТаблицы, ",");

	МассивСтруктур = Новый Массив;
	Для каждого СтрокаТаблицыЗначений Из ТаблицаЗначений Цикл
		СтруктураСтроки = Новый Структура(СтрокаКолонок);
		ЗаполнитьЗначенияСвойств(СтруктураСтроки, СтрокаТаблицыЗначений);
		МассивСтруктур.Добавить(СтруктураСтроки);
	КонецЦикла;

	Возврат МассивСтруктур;

КонецФункции // ТаблицаЗначенийВМассивСтруктур()

Функция МассивСтруктурВТаблицуЗначений(МассивСтруктур)

	ТаблицаЗначений = Новый ТаблицаЗначений;
	ДобавлятьКолонки = Истина;
	
	Для каждого СтруктураСтроки Из МассивСтруктур Цикл
		
		Если ДобавлятьКолонки Тогда
			Для каждого ЭлементСтруктуры Из СтруктураСтроки Цикл
				ТаблицаЗначений.Колонки.Добавить(ЭлементСтруктуры.Ключ);
			КонецЦикла;
			ДобавлятьКолонки = Ложь;
		КонецЕсли;

		НоваяСтрока = ТаблицаЗначений.Добавить();
		ЗаполнитьЗначенияСвойств(НоваяСтрока, СтруктураСтроки); 
	
	КонецЦикла;

	Возврат ТаблицаЗначений;

КонецФункции // МассивСтруктурВТаблицуЗначений()

Функция СписокСтруктурВТаблицуЗначений(СписокСтруктур)

	ТаблицаЗначений = Новый ТаблицаЗначений;
	Для каждого ЭлементСписка Из СписокСтруктур Цикл
		СтруктураСтроки = ЭлементСписка.Значение;
		Если Не ТаблицаЗначений.Колонки.Количество() Тогда
			Для каждого ЭлементСтруктуры Из СтруктураСтроки Цикл
				ТаблицаЗначений.Колонки.Добавить(ЭлементСтруктуры.Ключ);
			КонецЦикла;
		КонецЕсли;
		НоваяСтрока = ТаблицаЗначений.Добавить();
		ЗаполнитьЗначенияСвойств(НоваяСтрока, СтруктураСтроки); 
	КонецЦикла;

	Возврат ТаблицаЗначений;

