	Выборка = РезультатЗапроса.Выбрать();
	
	Пока Выборка.Следующий() Цикл
		СтрокаНз = Нз.Добавить();
		СтрокаНз.Период = Выборка.ДатаНачала;
		СтрокаНз.Активность = Истина;
