// Добавляет новую колонку или обновляет существующую
// Если колонка уже есть, то обновляет свойства Заголовок и Ширина
// Источник: https://github.com/SeiOkami/CollectionMethodsOneS/issues/23
// 
// Параметры:
//  ТаблицаЗначений  - ТаблицаЗначений - Таблица значений, в которую нужно добавить колонку
//  Имя              - Строка - Имя колонки
//  Тип              - ОписаниеТипов, Неопределено - Объект, описывающий допустимые типы значений для колонки. 
//                 Если параметр не указан, в колонке можно будет хранить значение любого типа.
//  Заголовок        - Строка, Неопределено - Заголовок колонки таблицы значений.
//                 Используется при визуальном отображении таблицы значений.
//  Ширина           - Число, Неопределено - Ширина колонки в символах.
//                 Используется при визуальном отображении таблицы значений.
//
// Возвращаемое значение:
//   КолонкаТаблицыЗначений - добавленная (или найденная) колонка 
//
// Пример:
// 	ТЗ = Новая ТаблицаЗначений;
// 	К1 = ОбновленнаяКолонкаТаблицы(ТЗ, "К1"); //ТЗ.Колонки.Количество() = 1
// 	К2 = ОбновленнаяКолонкаТаблицы(ТЗ, "К2"); //ТЗ.Колонки.Количество() = 2
// 	К1 = ОбновленнаяКолонкаТаблицы(ТЗ, "К1"); //ТЗ.Колонки.Количество() = 2
//
Функция ОбновленнаяКолонкаТаблицы(Знач ТаблицаЗначений, Знач Имя, 
	Знач Тип = Неопределено, Знач Заголовок = Неопределено, Знач Ширина = Неопределено) Экспорт
	
	Колонка	= ТаблицаЗначений.Колонки.Найти(Имя);
	Если Колонка = Неопределено Тогда
		Колонка	= ТаблицаЗначений.Колонки.Добавить(Имя, Тип);
	КонецЕсли;
	
	Если Заголовок <> Неопределено Тогда
		Колонка.Заголовок	= Заголовок;
	КонецЕсли;
	
	Если Ширина <> Неопределено Тогда
		Колонка.Ширина	= Ширина;
	КонецЕсли;
	
	Возврат Колонка;
	
КонецФункции

// Возвращает новый элемент отбора построителя
// Источник: https://github.com/SeiOkami/CollectionMethodsOneS/issues/17
// 
// Параметры:
//  Построитель    - ПостроительЗапроса, ПостроительОтчета - Построитель, в которой необходимо добавить элемент отбора
//  ПолеОтбора     - Строка - Имя поля отбора
//  ЗначениеОтбора - Произвольный
//                 - Массив из Произвольный
//                 - ФиксированныйМассив из Произвольный
//  ВидОтбора      - Строка, ВидСравнения - Вид сравнения отбор в виде строки
//                 Если Неопределено, то для списков будет ВСписке, а для остальных Равно
//
// Возвращаемое значение:
//   ЭлементОтбора
//   
// Пример:
// 	ЭлементОтбора = Построитель_ДобавитьОтбор(Построитель, "Код", "123");
// 	ЭлементОтбора = Построитель_ДобавитьОтбор(Построитель, "Номер", 1, "Больше");
// 	ЭлементОтбора = Построитель_ДобавитьОтбор(Построитель, "Ссылка", МассивСсылок);
//   
Функция Построитель_ДобавитьОтбор(Знач Построитель, Знач ПолеОтбора, Знач ЗначениеОтбора, Знач ВидОтбора = Неопределено) Экспорт
	
    ЭлементОтбора = Построитель.Отбор.Добавить(ПолеОтбора);
    ЭлементОтбора.Использование = Истина;
	
	Если ТипЗнч(ЗначениеОтбора) = Тип("Массив") 
		ИЛИ ТипЗнч(ЗначениеОтбора) = Тип("ФиксированныйМассив") Тогда
		УстанавливаемоеЗначение = Новый СписокЗначений; //СписокЗначений из Неопределено
		Для Каждого Значение Из ЗначениеОтбора Цикл
			УстанавливаемоеЗначение.Добавить(Значение);
		КонецЦикла;
		ЭтоСписок = Истина;
	Иначе
		 УстанавливаемоеЗначение = ЗначениеОтбора; //@skip-check statement-type-change
		 ЭтоСписок = (ТипЗнч(ЗначениеОтбора) = Тип("СписокЗначений"));
	КонецЕсли;
	
	Если ВидОтбора = Неопределено Тогда
		ЭлементОтбора.ВидСравнения = ?(ЭтоСписок, ВидСравнения.ВСписке, ВидСравнения.Равно);
	ИначеЕсли ТипЗнч(ВидОтбора) = Тип("ВидСравнения") Тогда
		ЭлементОтбора.ВидСравнения = ВидОтбора;
	Иначе
		ЭлементОтбора.ВидСравнения = ВидСравнения[Строка(ВидОтбора)]; //@skip-check statement-type-change
	КонецЕсли;
	
	ЭлементОтбора.Значение = УстанавливаемоеЗначение;
	
	Возврат ЭлементОтбора;
	
КонецФункции

// Сворачивает табличную часть по всем колонкам (Числовые колонки при этом суммируются). 
// Источник: https://github.com/SeiOkami/CollectionMethodsOneS/issues/22
//
// Параметры:
//  ТабличнаяЧасть - ТабличнаяЧасть - ТЧ объекта, которую нужно свернуть
//
// Пример:
// 	СвернутьТабличнуюЧасть(ЭтотОбъект.ТабличнаяЧасть);
// 	//Строки свернуться по значениям колонок, числовые при этом просуммируются
//
Процедура СвернутьТабличнуюЧасть(Знач ТабличнаяЧасть) Экспорт
	
	Ресурсы = Новый Массив; // Массив из Строка
	Измерения = Новый Массив; // Массив из Строка
	
	МетаданныеТабличнойЧасти = Метаданные.НайтиПоТипу(ТипЗнч(ТабличнаяЧасть)); // ОбъектМетаданныхТабличнаяЧасть
	Для Каждого МетаданныеКолонки Из МетаданныеТабличнойЧасти.Реквизиты Цикл
		ИмяКолонки = МетаданныеКолонки.Имя;
		Если МетаданныеКолонки.Тип.СодержитТип(Тип("Число")) Тогда
			Ресурсы.Добавить(ИмяКолонки);
		Иначе
			Измерения.Добавить(ИмяКолонки);
		КонецЕсли;
	КонецЦикла;
	
	ИменаИзмерений = СтрСоединить(Измерения, ",");
	ИменаРесурсов = СтрСоединить(Ресурсы, ",");
	
	ТабличнаяЧасть.Свернуть(ИменаИзмерений, ИменаРесурсов);
	
КонецПроцедуры

// Возвращает описание таблицы значений по полному имени таблицы базы данных
// Например "Справочник.Валюты" или "РегистрСведений.КурсыВалют"
// Источник: https://github.com/SeiOkami/CollectionMethodsOneS/issues/21
//
// Параметры:
//  ПолноеИмя  - Строка - Полное имя таблицы базы данных
//
// Возвращаемое значение:
//   ТаблицаЗначений
//
Функция СтруктураТаблицыБазы(Знач ПолноеИмя) Экспорт
	
	ТекстЗапроса = СтрШаблон("ВЫБРАТЬ ПЕРВЫЕ 0 * ИЗ %1", ПолноеИмя);
	СхемаЗапроса = Новый СхемаЗапроса();
	СхемаЗапроса.УстановитьТекстЗапроса(ТекстЗапроса);
	
	Результат = Новый ТаблицаЗначений();
	Для Каждого Колонка Из СхемаЗапроса.ПакетЗапросов.Получить(0).Колонки Цикл
		
		ВременнаяСтруктура = Новый Структура("Колонки", Неопределено);
		ЗаполнитьЗначенияСвойств(ВременнаяСтруктура, Колонка);
		Если ЗначениеЗаполнено(ВременнаяСтруктура.Колонки) Тогда
			ТипЗначения = Новый ОписаниеТипов("ТаблицаЗначений");
		Иначе
			ТипЗначения = Колонка.ТипЗначения;
		КонецЕсли;
		
		Результат.Колонки.Добавить(Колонка.Псевдоним, ТипЗначения);
		
	КонецЦикла;
	
	Возврат Результат;
	
КонецФункции

// Является ли переданный тип менеджером записи регистра сведений
// К сожалению, либо этот вариант, либо тупо проверка представления типа
// Источник: https://github.com/SeiOkami/CollectionMethodsOneS/issues/25
// 
// Параметры:
//  ТипЗначения - Тип
//
// Возвращаемое значение:
//   Булево
Функция ЭтоМенеджерЗаписиРегистраСведений(Знач ТипЗначения) Экспорт
    
    ОбъектМетаданных = Метаданные.НайтиПоТипу(ТипЗначения);
	Если ТипЗнч(ОбъектМетаданных) = Тип("ОбъектМетаданных") И Метаданные.РегистрыСведений.Содержит(ОбъектМетаданных) Тогда
		ТипМенеджераЗаписи = Тип("РегистрСведенийМенеджерЗаписи." + ОбъектМетаданных.Имя);
        ЭтоМенеджерЗаписи  = (ТипМенеджераЗаписи = ТипЗначения);
    Иначе
        ЭтоМенеджерЗаписи  = Ложь;
    КонецЕсли;
    
    Возврат ЭтоМенеджерЗаписи;
    
КонецФункции

// Функция возвращает копию переданной таблицы значений, но исключая из всех колонок тип Null
// Бывает полезна для обработки выгрузки запроса, в котором у каждой колонки есть тип Null
// Источник: https://github.com/SeiOkami/CollectionMethodsOneS/issues/24
// 
// Параметры:
//  ТаблицаЗначений - ТаблицаЗначений
//
// Возвращаемое значение:
//   ТаблицаЗначений - Таблица без Null
//
// Пример:
// 	ВыгрузкаЗапроса = Запрос.Выполнить().Выгрузить(); //Все колонки содержат тип Null
// 	ВыгрузкаБезNull = ТаблицаЗначенийБезNull(ВыгрузкаЗапроса); //Колонки без типа Null
//
Функция ТаблицаЗначенийБезNull(Знач ТаблицаЗначений) Экспорт
	
	НоваяТаблица = Новый ТаблицаЗначений;
	Для Каждого ТекущаяКолонка Из ТаблицаЗначений.Колонки Цикл
		ОписаниеТипа = Новый ОписаниеТипов(ТекущаяКолонка.ТипЗначения, , "NULL");
        НоваяТаблица.Колонки.Добавить(ТекущаяКолонка.Имя, ОписаниеТипа,
			ТекущаяКолонка.Заголовок, ТекущаяКолонка.Ширина);
    КонецЦикла;
	
	Для Каждого ТекущаяСтрока Из ТаблицаЗначений Цикл
        ЗаполнитьЗначенияСвойств(НоваяТаблица.Добавить(), ТекущаяСтрока);
    КонецЦикла;
    
    Возврат НоваяТаблица;

КонецФункции

// Возвращает новый объект переданного типа.
// Источник: https://github.com/SeiOkami/CollectionMethodsOneS/issues/20
//  
// Параметры:
//  Тип - Строка, Тип - Тип или имя типа
// 
// Возвращаемое значение:
//  Произвольный
//
// Примеры:
// 	Результат = НовыйОбъект("Структура");
// 	Результат = НовыйОбъект("УсловноеОформлениеКомпоновкиДанных");
// 	Результат = НовыйОбъект("HTTPОтвет");
//
Функция НовыйОбъект(Знач Тип) Экспорт
	
	Типы = Неопределено;
	Если ТипЗнч(Тип) = Тип("Тип") Тогда
		Типы = Новый Массив; // Массив из Тип
		Типы.Добавить(Тип);
	Иначе
		Типы = Тип;
	КонецЕсли;
	
	ОписаниеТипа = Новый ОписаниеТипов(Типы);
	
	Возврат ОписаниеТипа.ПривестиЗначение();
	
КонецФункции

Функция ПолучитьПараметрыКакСоответствие(Тело)Экспорт
	
	Результат = Новый Соответствие;
	Тело = РаскодироватьСтроку(Тело, СпособКодированияСтроки.КодировкаURL, "UTF-8");
	Тело = СтрЗаменить(Тело, "+", " ");
	ПарметрыЗначения = СтроковыеФункцииКлиентСервер.РазложитьСтрокуВМассивПодстрок(Тело, "&");
	Для Каждого Пар Из ПарметрыЗначения Цикл
		мПар = СтроковыеФункцииКлиентСервер.РазложитьСтрокуВМассивПодстрок(Пар, "=");
		Если мПар.Количество() > 1 Тогда
			СущЗначениеПараметра = Результат.Получить(мПар[0]);
			
			//Если в структуре нет такого параметра, просто его добавляем.
			Если СущЗначениеПараметра = Неопределено Тогда 
				Результат.Вставить(мПар[0], мПар[1]);
			Иначе
				//Если такой параметр есть и значени его находится в массиве, то добавляем
				//текущий параметр в массив.
				Если ТипЗнч(СущЗначениеПараметра) = Тип("Массив") Тогда 
					СущЗначениеПараметра.Добавить(мПар[1]);
					Результат.Вставить(мПар[0], СущЗначениеПараметра);
					
					//Если это второе значение параметра, то добавляем уже существующее и текущее
					//значение в массив.	
				Иначе 
					МассивЗначЭтогоПараметра = Новый Массив();
					МассивЗначЭтогоПараметра.Добавить(СущЗначениеПараметра);
					МассивЗначЭтогоПараметра.Добавить(мПар[1]);
					Результат.Вставить(мПар[0], МассивЗначЭтогоПараметра);
				КонецЕсли;
			КонецЕсли;
			
		КонецЕсли;
	КонецЦикла;
	
	Возврат Результат;
	
КонецФункции

Функция ПолучитьПараметры(Тело)Экспорт
	
	Результат = Новый Структура;
	Тело = РаскодироватьСтроку(Тело, СпособКодированияСтроки.КодировкаURL, "UTF-8");
	Тело = СтрЗаменить(Тело, "+", " ");
	ПарметрыЗначения = СтроковыеФункцииКлиентСервер.РазложитьСтрокуВМассивПодстрок(Тело, "&");
	Для Каждого Пар Из ПарметрыЗначения Цикл
		
		мПар = СтроковыеФункцииКлиентСервер.РазложитьСтрокуВМассивПодстрок(Пар, "=");
		Если мПар.Количество() > 1 Тогда
			СущЗначениеПараметра = "";
			
			Попытка
				Результат.Свойство(мПар[0], СущЗначениеПараметра);
			Исключение
				Продолжить;
			КонецПопытки;
			
			//Если в структуре нет такого параметра, просто его добавляем.
			Если ПустаяСтрока(СущЗначениеПараметра) Тогда 
				Результат.Вставить(мПар[0], мПар[1]);
			Иначе
				
				//Если такой параметр есть и значени его находится в массиве, то добавляем
				//текущий параметр в массив.
				Если ТипЗнч(СущЗначениеПараметра) = Тип("Массив") Тогда 
					СущЗначениеПараметра.Добавить(мПар[1]);
					Результат.Вставить(мПар[0], СущЗначениеПараметра);
					
					//Если это второе значение параметра, то добавляем уже существующее и текущее
					//значение в массив.	
				Иначе 
					МассивЗначЭтогоПараметра = Новый Массив();
					МассивЗначЭтогоПараметра.Добавить(СущЗначениеПараметра);
					МассивЗначЭтогоПараметра.Добавить(мПар[1]);
					Результат.Вставить(мПар[0], МассивЗначЭтогоПараметра);
				КонецЕсли;
			КонецЕсли;
		ИначеЕсли мПар.Количество() = 1 Тогда
			Если Не Результат.Свойство(мПар[0]) Тогда
				Результат.Вставить(мПар[0], "");
			КонецЕсли;
		КонецЕсли;
	КонецЦикла;
	
	Возврат Результат;
	
КонецФункции

Функция РазбитьНаКусочки(ОбщееКоличество, ОднаЧасть) Экспорт
	Частей = Цел(ОбщееКоличество / ОднаЧасть) + ?(ОбщееКоличество % ОднаЧасть > 0, 1, 0);

	Частное = ОбщееКоличество / Частей;
	МаксКусок = Цел(Частное) + ?(ОбщееКоличество % Частей > 0, 1, 0);
	Остаток = ОбщееКоличество % МаксКусок;

	Массив = Новый Массив;

	Если Остаток > 0 Тогда
		ОдинКусок = МаксКусок - 1;
		МеньшегоКолва = МаксКусок - Остаток;
		Для ъ = 1 по МеньшегоКолва Цикл
			Массив.Добавить(ОдинКусок);
		КонецЦикла;
	Иначе
		ъ = 1;
	КонецЕсли;

	ОдинКусок = МаксКусок;
	ъъ = ъ;
	Для ъ = ъъ по Частей Цикл
		Массив.Вставить(0, ОдинКусок);
	КонецЦикла;

//	ВсегоВМассиве = 0;
//	Для Каждого Элем из Массив Цикл
//		ВсегоВМассиве = ВсегоВМассиве + Элем;
//	КонецЦикла;

	Возврат Массив;
КонецФункции  // РазбитьНаКусочки

Функция РазбитьСписокТоваров(Знач списТоваров, МаксТоваров = 150)
	#Если Сервер И Не Сервер Тогда  // для типизации в конфигураторе
		списТоваров = Новый СписокЗначений;
	#КонецЕсли

	мТовары = списТоваров.ВыгрузитьЗначения();

	КоличествоТоваров = мТовары.Количество();
	мКусочки = РазбитьНаКусочки(КоличествоТоваров, МаксТоваров);

	ммТовары = Новый Массив;
	Для Каждого ЧислоТоваров Из мКусочки Цикл
		мПодСписок = Новый Массив;
		Для ъ = 1 По ЧислоТоваров Цикл
			мПодСписок.Добавить(мТовары[0]);
			мТовары.Удалить(0);
		КонецЦикла;

		ммТовары.Добавить(мПодСписок);
	КонецЦикла;

	Возврат ммТовары;
КонецФункции  // РазбитьСписокТоваров

