//Процедуру нужно расположить в общем модуле с включенными флагами "Сервер" и "Вызов сервера"
Процедура Пауза(КоличествоСекунд) Экспорт
	
	Если ТипЗнч(КоличествоСекунд) <> Тип("Число") ИЛИ КоличествоСекунд = 0 Тогда
		Возврат; // Чтобы не произошло бесконечной паузы (зависания)
	КонецЕсли; 
	
	ФоновоеЗадание = ПолучитьТекущийСеансИнформационнойБазы().ПолучитьФоновоеЗадание(); // Для проверки, работаем ли мы в фоновом задании
	
	Если ФоновоеЗадание = Неопределено Тогда
		
		// Алгоритм запуска фонового задания и ожидания завершения по времени
		
		Параметры = Новый Массив(1);
		Параметры.Установить(0, КоличествоСекунд);
		ИмяМетода = "_ФоновоеЗадание.Пауза"; // Полное имя метода текущей процедуры, с указанием общего модуля
		
		// Запускаем фоновое задание без использования расширений конфигурации (снижаем нагрузку на сервер)
		ФоновоеЗадание = РасширенияКонфигурации.ВыполнитьФоновоеЗаданиеБезРасширений(ИмяМетода, Параметры);
		
	КонецЕсли; 
	
	ФоновоеЗадание.ОжидатьЗавершенияВыполнения(КоличествоСекунд);
	
КонецПроцедуры

// Настраивает форму списка так, чтобы она стала формой выбора.
// Позволяет полноценно использовать одну форму как в качестве основной формы списка, так и формы выбора
//
// Параметры:
//  Форма  - ФормаКлиентскогоПриложения - управляемая форма
//  ИмяЭлемента  - Строка - Имя элемента динамического списка
//
Процедура ИнициализироватьФормуВыбора(Форма, ИмяЭлемента = "Список") Экспорт
	
	ЭлементФормы = Форма.Элементы.Найти(ИмяЭлемента);
	ЭлементФормы.РежимВыбора = (Форма.Параметры.РежимВыбора = Истина);
	ЭлементФормы.МножественныйВыбор = (Форма.Параметры.МножественныйВыбор = Истина);
	
	Если ЭлементФормы.РежимВыбора И НЕ ЗначениеЗаполнено(Форма.КлючНазначенияИспользования) Тогда
		СтандартныеПодсистемыСервер.УстановитьКлючНазначенияФормы(Форма, "РежимВыбора");
	КонецЕсли;
	
КонецПроцедуры

Процедура НайтиСсылкуНаОрганизациюВРегистрахИзмеренияхРН (ОбъектДляПоиска, ТипОбъекта)

Для Каждого Регистр Из Метаданные.РегистрыНакопления Цикл
	
	Для Каждого Измерение Из Регистр.Измерения Цикл
		
		МассивТипов = Новый Массив;
		МассивТипов.Добавить(ТипОбъекта);
		
		Если Измерение.Тип = Новый ОписаниеТипов(МассивТипов) Тогда
			
			ИмяРегистра = Регистр.Имя;
			ИмяИзмерения = Измерение.Имя;
			
			Запрос = Новый Запрос;
			Запрос.Текст = "ВЫБРАТЬ
			|	" + ИмяРегистра + "." + ИмяИзмерения + ",
			|	СУММА(1) КАК КоличествоЗаписей
			|ИЗ
			|	РегистрНакопления." + ИмяРегистра + " КАК " + ИмяРегистра + "
			|ГДЕ
			|  " + ИмяРегистра + "." + ИмяИзмерения + " = &ИскомыйОбъект" + "
			|СГРУППИРОВАТЬ ПО
			|	" + ИмяРегистра + "." + ИмяИзмерения + "";
			Запрос.УстановитьПараметр("ИскомыйОбъект", ТипОбъекта);
			Результат = Запрос.Выполнить().Выбрать();
			Выборка = Запрос.Выполнить().Выбрать();
			
			Если Выборка.Следующий() Тогда
				Сообщить("В РН " + ИмяРегистра + " существует " + Строка(Выборка.КоличествоЗаписей) + " записей"); 				
			КонецЕсли;
			
		КонецЕсли;
	КонецЦикла;
КонецЦикла;
	
КонецПроцедуры

Процедура ВыполнитьУдалениеДокументов(НачальнаяДата, КонечнаяДата, Организация) Экспорт
	
	Запрос = Новый Запрос;
	Запрос.УстановитьПараметр("НачальнаяДата", НачальнаяДата);			   
	Запрос.УстановитьПараметр("КонечнаяДата", КонечнаяДата);
	Запрос.УстановитьПараметр("Организация", Организация);
	
	Для Каждого МетаДокумент из Метаданные.Документы Цикл
		
		ОбработкаПрерыванияПользователя();
		
		Если МетаДокумент.Реквизиты.Найти("Организация") = Неопределено Тогда
			Продолжить;
		КонецЕсли;	
		
		Запрос.Текст = "ВЫБРАТЬ
		|	УдаляемыйДокумент.Ссылка
		|ИЗ
		|	Документ.ЧекККМ КАК УдаляемыйДокумент
		|ГДЕ
		|	УдаляемыйДокумент.Дата МЕЖДУ &НачальнаяДата И &КонечнаяДата
		|	И УдаляемыйДокумент.Организация = &Организация
		|	И НЕ УдаляемыйДокумент.ПометкаУдаления
		|
		|УПОРЯДОЧИТЬ ПО
		|	УдаляемыйДокумент.Дата";
		Запрос.Текст = СтрЗаменить(Запрос.Текст, "ЧекККМ", МетаДокумент.Имя);
		Выборка = Запрос.Выполнить().Выбрать;
		
		Если Не Выборка.Количество() Тогда
			Продолжить;
		КонецЕсли;	
		
		МассивДокументов = Новый Массив;
		
		МассивФЗ = Новый Массив;
		КоличествоЗаданий = 20; // количество фоновых заданий для каждого вида документа 
		КоличествоДанныхДляЗадания = 800; // количество документов, обрабатываемых одним фоновым заданием
		МассивДанныхЗадания = Новый Массив;
		Пока Выборка.Следующий() Цикл
			МассивДанныхЗадания.Добавить(Выборка.Ссылка);
			// если набралось достаточно документов для запуска ФЗ - идем дальше
			Если МассивДанныхЗадания.Количество() = КоличествоДанныхДляЗадания Тогда
				// проверяем есть ли свободные ФЗ, иначе ждем
				Пока МассивФЗ.Количество() = КоличествоЗаданий Цикл
					Для Каждого ФЗ ИЗ МассивФЗ Цикл
						ОтборФЗ = Новый Структура;
						ОтборФЗ.Вставить("УникальныйИдентификатор", ФЗ); 
						МассивАктивныхЗаданий = ФоновыеЗадания.ПолучитьФоновыеЗадания(ОтборФЗ);
						Для Каждого Задание Из МассивАктивныхЗаданий Цикл
							Если НЕ Задание.Состояние = СостояниеФоновогоЗадания.Активно Тогда
								МассивФЗ.Удалить(МассивФЗ.Найти(ФЗ));
								Прервать; // выйдем из "бесконечного" цикла, когда хотя бы одно из заданий закончилось
							КонецЕсли;
						КонецЦикла;
					КонецЦикла; 
				КонецЦикла;
				// запускаем ФЗ
				МассивПараметров = Новый Массив;
