				МассивФЗ.Добавить(ФЗ.УникальныйИдентификатор);
				МассивДанныхЗадания = Новый Массив;
			КонецЕсли; // КоличествоДанныхДляЗадания
		КонецЦикла;
		// если не дошли до ограничения по количеству документов в ФЗ - запускаем единственное
