		МеньшаяДата = ВремДата;
		
	ИначеЕсли БольшаяДата = МеньшаяДата Тогда 
		
		Возврат 0;
		
	КонецЕсли;
	
	Разница = БольшаяДата - МеньшаяДата;	
	
	Если Тип = "сек" или Тип = "секунда" или Тип = "секунды" Тогда
		Возврат Разница;
