&НаСервере
Функция УстановитьЗначениеДопРеквизита(ЭлементСправочника,ИмяДопРеквизит,ЗначениеДопРеквизит)
    
    ЭлементОбъект = ЭлементСправочника.ПолучитьОбъект();
    ИмяРеквизита = ПланыВидовХарактеристик.ДополнительныеРеквизитыИСведения.НайтиПоНаименованию(ИмяДопРеквизит); 
    Если ИмяРеквизита = ПланыВидовХарактеристик.ДополнительныеРеквизитыИСведения.ПустаяСсылка() тогда
        Возврат ""
    КонецЕсли;
    СтрокаДопРеквизита = ЭлементОбъект.ДополнительныеРеквизиты.Найти(ИмяРеквизита,"Свойство");
    Если   СтрокаДопРеквизита   = неопределено тогда
        СтрокаДопРеквизита = ЭлементОбъект.ДополнительныеРеквизиты.Добавить();
    КонецЕсли;
    СтрокаДопРеквизита.Свойство = ИмяРеквизита;
    СтрокаДопРеквизита.Значение = ЗначениеДопРеквизит;
    ЭлементОбъект.Записать();
    Возврат Истина;
    
КонецФункции

//     ДСумма = ПолучитьЗначениеДопРеквизита (СсылкаНаДокумент.ДоговорКонтрагента, "НачальнаяСуммаДолга");
Функция ПолучитьЗначениеДопРеквизита(ЭлементСправочника,ИмяДопРеквизит)
    
    ИмяРеквизита = ПланыВидовХарактеристик.ДополнительныеРеквизитыИСведения.НайтиПоНаименованию(ИмяДопРеквизит); 
    СтрокаДопРеквизита = ЭлементСправочника.ДополнительныеРеквизиты.Найти(ИмяРеквизита,"Свойство");
    Если   СтрокаДопРеквизита   = неопределено тогда
        возврат ""
    иначе    
    возврат СтрокаДопРеквизита.Значение;
    КонецЕсли;
КонецФункции
        
// Получаем Свойство и Значение дополнительных реквизитов по Заголовку 
// (передЗаписьюНаСервере)
// Работает для существующего элемента
 &НаСервере       
        Для Каждого ТекущаяСтрока Из ТекущийОбъект.ДополнительныеРеквизиты Цикл
            Если ТекущаяСтрока.Свойство.Заголовок = "P/N Вендора" Тогда
                ПНВендораСвойство = ТекущаяСтрока.Свойство;
                ПНВендораЗначение = ТекущаяСтрока.Значение;
            КонецЕсли;
            
            Если ТекущаяСтрока.Свойство.Заголовок = "P/N Производителя" Тогда
                ПНПроизводителяСвойство = ТекущаяСтрока.Свойство;
                ПНПроизводителяЗначение = ТекущаяСтрока.Значение;
            КонецЕсли;
        КонецЦикла;         
 
 
// Получение текущих незаписанных значений из формы 
// (передЗаписьюНаСервере)       
// Работает для записанного и незаписанного элемента
     РеквизитыФормы = ЭтаФорма.ПолучитьРеквизиты();
    
    Для сч = 0 По РеквизитыФормы.Количество()-1 Цикл // обход массива реквизитов
        Если РеквизитыФормы[сч].Заголовок = "P/N Вендора" Тогда // имя дополнительного реквизита 
            ПНВендораЗначение = ЭтаФорма[РеквизитыФормы[сч].Имя];
        КонецЕсли;
    КонецЦикла;    
 
// получаем свойства ДополнительныхРеквизитов из ПланаВидовХарактеристик по их Заголовкам
    Запрос = Новый Запрос;
    Запрос.Текст = 
    "ВЫБРАТЬ
    |    ДополнительныеРеквизитыИСведения.Ссылка,
    |    ДополнительныеРеквизитыИСведения.Заголовок
    |ИЗ
    |    ПланВидовХарактеристик.ДополнительныеРеквизитыИСведения КАК ДополнительныеРеквизитыИСведения";    
    РезультатЗапроса = Запрос.Выполнить();
    
    ВыборкаДетальныеЗаписи = РезультатЗапроса.Выбрать();
    
    Пока ВыборкаДетальныеЗаписи.Следующий() Цикл
        Если ВыборкаДетальныеЗаписи.Заголовок = "P/N Вендора" Тогда // имя дополнительного реквизита 
            ПНВендораСвойство = ВыборкаДетальныеЗаписи.Ссылка;
        КонецЕсли;
    КонецЦикла;
     
// Проверка уникальности введенного дополнительного реквизита   
// (передЗаписьюНаСервере)       
// Работает для записанного и незаписанного элемента   
    Запрос = Новый Запрос;                       
    Запрос.Текст = 
    "ВЫБРАТЬ РАЗРЕШЕННЫЕ
    |    Номенклатура.Ссылка КАК Ссылка,
    |    NULL КАК Свойство,
    |    NULL КАК Значение
    |ИЗ
    |    Справочник.Номенклатура КАК Номенклатура 
    |
    |ОБЪЕДИНИТЬ ВСЕ
    |
    |ВЫБРАТЬ
    |    НоменклатураДополнительныеРеквизиты.Ссылка,
    |    НоменклатураДополнительныеРеквизиты.Свойство,
    |    НоменклатураДополнительныеРеквизиты.Значение
    |ИЗ
    |    Справочник.Номенклатура.ДополнительныеРеквизиты КАК НоменклатураДополнительныеРеквизиты
    |ГДЕ
    |    НоменклатураДополнительныеРеквизиты.Свойство = &ВыбСвойство
    |    И НоменклатураДополнительныеРеквизиты.Значение = &ВыбЗначение";

    Запрос.УстановитьПараметр("ВыбСвойство",ПНПроизводителяСвойство); // ссылка на ПВХ (название реквизита)
    Запрос.УстановитьПараметр("ВыбЗначение",ПНПроизводителяЗначение); // значение для поиска                                
    РезультатЗапроса = Запрос.Выполнить();
    
    ВыборкаДетальныеЗаписи = РезультатЗапроса.Выбрать();     
                                              
    Пока ВыборкаДетальныеЗаписи.Следующий() Цикл
        Если СокрЛП(ВыборкаДетальныеЗаписи.Значение) = "" Тогда // пропускаем NULLы 
            Продолжить;
        КонецЕсли;
        Если ТекущийОбъект.ссылка <> ВыборкаДетальныеЗаписи.ссылка Тогда // если найденный объект - не наш объект
                        // для нового объекта ТекущийОбъект.ссылка = Пустая() и тоже работает
            Отказ = Истина;
            Сообщить ("Введенное значение P/N Производителя уже присутствует в справочнике!");
        КонецЕсли;
    КонецЦикла;

//для документа
Сообщение = Новый СообщениеПользователю;
Сообщение.Текст = "Реквизит1 не заполнен";
Сообщение.Поле = "ИмяПоляФормы";
