    КонецЕсли; 

    КоличествоПроводок = Проводки.Количество();

    Если КоличествоПроводок > 0 Тогда
        ТекущаяАктивностьПроводок = Проводки[0].Активность;
        НужнаяАктивностьПроводок  = НЕ ПометкаУдаления;

