        // Записываем элемент справочника вручную
        НоменклатураЗаписатьXML(ЗаписьXML; Данные);
    Иначе

        // Записываем данные с помощью стандартного метода
        ЗаписатьXML(ЗаписьXML; Данные);
    КонецЕсли

